### Rationale:
- **Recursive (default):** Matches tree structure intuitively, cleaner code, aligns with your earlier decision on `inorder()`. Python's ~1000 recursion limit handles typical BSTs (balanced trees up to ~10 levels).
- **Iterative (alternative):** Provide `search_iterative()` and `insert_iterative()` for deep/unbalanced trees or strict memory constraints.

### Implementation structure:
```python
def insert(self, value):
    """Default recursive insert."""
    self.root = self._insert_recursive(self.root, value)

def _insert_recursive(self, node, value):
    if node is None:
        return Node(value)
    if value < node.value:
        node.left = self._insert_recursive(node.left, value)
    elif value > node.value:
        node.right = self._insert_recursive(node.right, value)
    return node

def search(self, value):
    """Default recursive search."""
    return self._search_recursive(self.root, value)

def _search_recursive(self, node, value):
    if node is None:
        return False
    if value == node.value:
        return True
    elif value < node.value:
        return self._search_recursive(node.left, value)
    else:
        return self._search_recursive(node.right, value)

def search_iterative(self, value):
    """Alternative for deep trees."""
    node = self.root
    while node:
        if value == node.value:
            return True
        node = node.left if value < node.value else node.right
    return False
```

